	  else 
		GameData::Move.each { |i| smoves.push(i.id) if (i.type==pkmn.types[0] || i.type==pkmn.types[1])}
	  end
	  for i in smoves
		  moves.push(i) if !pkmn.hasMove?(i) && !moves.include?(i) && validmove(i) 
	  end
	end
	if $game_variables[MOVETUTOR]==5    #Alphabetmon
